import{_ as r,o as t,c as l,a2 as o}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F15: 關係人交易與利益輸送風險 - 財務審計專家 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/2492_華新科/20260512/F15_關係人交易與利益輸送風險.md","filePath":"審計報告庫/財務審計/2492_華新科/20260512/F15_關係人交易與利益輸送風險.md"}'),i={name:"審計報告庫/財務審計/2492_華新科/20260512/F15_關係人交易與利益輸送風險.md"};function e(n,a,s,h,d,_){return t(),l("div",null,[...a[0]||(a[0]=[o('<h1 id="f15-關係人交易與利益輸送風險-財務審計專家-審計報告" tabindex="-1">F15: 關係人交易與利益輸送風險 - 財務審計專家 審計報告 <a class="header-anchor" href="#f15-關係人交易與利益輸送風險-財務審計專家-審計報告" aria-label="Permalink to &quot;F15: 關係人交易與利益輸送風險 - 財務審計專家 審計報告&quot;">​</a></h1><blockquote><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p></blockquote><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>是否存在異常大額的關係人交易？定價是否符合市場行情？是否存在利益輸送或虛增利潤風險？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：關係人銷貨0.6%、進貨0.9%，遠低5%警戒線。無異常資金貸與，治理透明度高，利益輸送風險極低。</li><li><strong>風險評級</strong>：極低</li><li><strong>數據時效</strong>：截至2025年報</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>關係人銷貨佔比</strong>：0.6%(2.06億/363.7億)。風險閥值5%，遠低於警戒線。vs 2024年0.6%(1.95億/347.6億)，變動微小。</li><li><strong>關係人進貨佔比</strong>：0.9%(2.81億/301.6億)。vs 2024年0.9%(2.43億/282.7億)，同樣極低且穩定。</li><li><strong>應收/應付關係人</strong>：應收0.84億(佔總AR 0.8%)、應付0.89億(佔總AP約1-2%)。金額極微。</li><li><strong>診斷見解</strong>：無議題，過關。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="_1-關係人交易規模" tabindex="-1">1. 關係人交易規模 <a class="header-anchor" href="#_1-關係人交易規模" aria-label="Permalink to &quot;1. 關係人交易規模&quot;">​</a></h3><ul><li><strong>銷貨對象</strong>：主要為關聯企業(1.97億)，如釜屋電機、佳邦科技等子公司。金額小，無營收灌水疑慮。</li><li><strong>進貨對象</strong>：全部來自關聯企業(2.81億)，主要為元件採購。金額佔比極低。</li><li><strong>與2024年對比</strong>：銷貨1.95億→2.06億(+5.3%)；進貨2.43億→2.81億(+15.6%)。微幅成長但基數極小。</li></ul><h3 id="_2-資金貸與與背書保證" tabindex="-1">2. 資金貸與與背書保證 <a class="header-anchor" href="#_2-資金貸與與背書保證" aria-label="Permalink to &quot;2. 資金貸與與背書保證&quot;">​</a></h3><ul><li><strong>資金貸與</strong>：合計約25-30億，全部為集團內部子公司間的短期資金融通(如華科香港控股貸與釜屋電機12.4億、雙信電機8.0億等)。母公司對子公司資金貸與期末無實際動支——管理審慎。</li><li><strong>背書保證</strong>：母為子背書保證(釜屋電機12.9億、Kamaya 7.2億)，合計約20億。對比母公司權益約400億，佔比約5%，風險可控。</li><li><strong>關聯企業權益法收益</strong>：5.9億(2025) vs 4.8億(2024)，佔稅前淨利15.8%。此為正常策略投資收益。</li></ul><h3 id="_3-治理透明度評估" tabindex="-1">3. 治理透明度評估 <a class="header-anchor" href="#_3-治理透明度評估" aria-label="Permalink to &quot;3. 治理透明度評估&quot;">​</a></h3><ul><li><strong>附註揭露完整</strong>：年報附註詳列關係人交易、資金貸與、背書保證各項明細，透明度良好。</li><li><strong>隸屬華新麗華集團</strong>：華新科為華新麗華集團成員，集團內交易主要發生在集團內部供應鏈整合，具有商業合理性。</li></ul><h2 id="💡-專家評析-多空雙向分析" tabindex="-1">💡 專家評析（多空雙向分析） <a class="header-anchor" href="#💡-專家評析-多空雙向分析" aria-label="Permalink to &quot;💡 專家評析（多空雙向分析）&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li><strong>雖極微但仍需留意關係企業獲利集中</strong>：權益法收益5.9億(佔稅前淨利15.8%)來自釜屋電機/松尾電機等關係企業。若這些公司獲利下滑，對合併獲利有間接影響。</li><li><strong>集團內資金貸與規模約30億的潛在風險</strong>：雖全為內部調度，但若某子公司出現財務危機，可能產生連鎖效應。不過此風險被分散至多家子公司，且已正常還款。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li><strong>關係人交易比例極低為治理優勢</strong>：0.6%的關係人銷貨比在同業中屬於非常低的水準(國巨約3-5%)，降低利益輸送風險。</li><li><strong>資金貸與管理紀律佳</strong>：母公司對子公司資金貸與期末無實際動支，且所有貸與皆有還款紀錄。子公司間的資金融通具備合約和利率計算，非無償調度。</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>關係人交易規模極小、揭露透明、資金貸與管理審慎，無利益輸送疑慮。是華新科治理結構的亮點之一。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><strong>年報補充</strong>：2025年報(第77-78頁關係人交易、第86頁資金貸與、第87頁背書保證、第90-103頁附表)</li><li><strong>查詢參數</strong>：stock_id=2492, 年報附註二八</li><li><strong>關鍵核對碼</strong>：2025年關係人銷貨205,881仟元/營收36,462,792仟元=0.56%；關係人進貨280,716仟元/COGS 30,163,204仟元=0.93%</li><li><strong>數據查詢日期</strong>：2026-05-12</li></ul>',24)])])}const c=r(i,[["render",e]]);export{u as __pageData,c as default};
